/// Find the shirt number for a given token, or `None`.
pub fn lookup(token: &str) -> Option<u32> {
    JIUFIGHT_TOKENS.iter().find(|(t, _)| *t == token).map(|(_, n)| *n)
}

/// Find the token for a given shirt number 1..=100.
pub fn token_for(n: u32) -> Option<&'static str> {
    JIUFIGHT_TOKENS.iter().find(|(_, sn)| *sn == n).map(|(t, _)| *t)
}
